# Replace lines in the file
def replace_dict_entries(content, section_key, new_entries):
    """Replace language entries within a specific LINES sub-dict."""
    count = 0

    # Find the LINES dict first
    lines_start = content.index('LINES = {')

    for lang, new_text in new_entries.items():
        escaped_lang = re.escape(lang)
        # Match: 'xx': "any text here" — handles embedded \n and unicode
        pattern = rf"('{escaped_lang}':\s*\")((?:[^\"]|\\\")*)(\")"

        # Find the section within LINES only
        section_start = content.find(f"'{section_key}':", lines_start)
        if section_start == -1:
            print(f"  Section '{section_key}' not found!")
            continue

        # Find the closing brace for this section
        brace_depth = 0
        section_body_start = content.index('{', section_start)
        for i in range(section_body_start, len(content)):
            if content[i] == '{':
                brace_depth += 1
            elif content[i] == '}':
                brace_depth -= 1
                if brace_depth == 0:
                    section_end = i + 1
                    break

        section_text = content[section_body_start:section_end]
        match = re.search(pattern, section_text)
        if match:
            old_full = match.group(0)
            new_full = match.group(1) + new_text + match.group(3)
            new_section = section_text.replace(old_full, new_full, 1)
            content = content[:section_body_start] + new_section + content[section_end:]
            count += 1
        else:
            print(f"  {section_key}/{lang}: NOT FOUND")
    return content, count

content, c1 = replace_dict_entries(content, 'greeting', NEW_GREETING)
print(f"Greeting: updated {c1}/{len(NEW_GREETING)} languages")

