content, c3 = replace_dict_entries(content, 'post_reveal', NEW_POST_REVEAL)
print(f"Post reveal: updated {c3}/{len(NEW_POST_REVEAL)} languages")

with open(FILEPATH, 'w', encoding='utf-8') as f:
    f.write(content)

